<template>
	<view class="page-container">
		<view class="collapse-box">
			<u-collapse v-if="itemList.length">
				<u-collapse-item :title="item.head" v-for="(item, index) in itemList" :key="index" :open="item.open"
					:disabled="item.disabled">
					<template #title>
						<view class="item-title">
							<text>{{item.add_time}}</text>
							<u-button size="mini" style="margin: 0;"
								@click.stop="removeCurrent(item.add_time)">删除当天</u-button>
						</view>
					</template>
					<view class="item-content">
						<view class="footmark-list">
							<view class="footmark-item" v-for="goods,index2 in item.goodsList" :key="index2"
								@click="$util.to('/pages/goods/detail?id='+goods.id)">
								<u-image :src="goods.goods_img" width="200" height="200" border-radius="10"
									:error-img="sysconfig.goods.default_goods_img"></u-image>
								<view class="price-box">
									<text>￥{{goods.goods_price}}</text>
									<!-- <text>￥{{goods.face_value}}</text> -->
								</view>
								<view class="name line1">{{goods.goods_name}}</view>
							</view>
						</view>
					</view>
				</u-collapse-item>
			</u-collapse>
			<u-empty v-else></u-empty>
		</view>
		<u-modal v-model="show" content="确定删除商品浏览足迹吗" title="" @confirm="delFootmark"
			:show-cancel-button="true"></u-modal>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				itemList: [],
				show: false,
				delForm: {
					create_time: '',
					ids: ''
				},
			};
		},
		onLoad(e) {
			this.fetchData()
		},
		methods: {
			async fetchData() {
				const data = await this.$u.api.goodsSeeLog()
				this.itemList = data.map((item, index) => {
					if (index == 0)
						item.open = true
					else
						item.open = false

					return item
				})
			},
			// 删除当天
			removeCurrent(addTime) {
				this.show = true
				this.delForm.create_time = addTime
				this.delForm.ids = 'all'
			},
			async delFootmark() {
				await this.$u.api.delGoodsSeeLog(this.delForm)
				this.$util.msg('删除成功');
				this.fetchData()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.page-container {
		background-color: #fff;

		.collapse-box {
			padding: 0 20rpx;
		}
	}

	.item-title {
		display: flex;
		width: 100%;
		justify-content: space-between;
		align-items: center;
		border-bottom: 1px solid #dcdfe6;
		padding-bottom: 10rpx;
	}

	.item-content {
		.footmark-list {
			display: flex;
			flex-direction: row;
			flex-wrap: wrap;

			.footmark-item {
				display: flex;
				flex-direction: column;
				flex-basis: calc(100%3);
				overflow: hidden;
				justify-content: center;
				padding: 10rpx;
				cursor: pointer;

				.price-box {
					width: 150rpx;
					overflow: hidden;

					&>text:nth-child(1) {
						font-size: 28rpx;
						font-weight: 700;
						color: #f10;
					}

					&>text:nth-child(2) {
						font-size: 24rpx;
						color: #b0b0b0;
						font-weight: 400;
						text-decoration: line-through;
						margin-left: 10rpx;
					}
				}

				.name {
					width: 150rpx;
				}
			}
		}
	}
</style>